import React, { useState, useEffect } from "react";
import ReactMapGL, { Marker, Popup } from "react-map-gl";
import 'mapbox-gl/dist/mapbox-gl.css';

function WorldMap() {
  const [viewport, setViewport] = useState({
    latitude: 20,
    longitude: 0,
    zoom: 1.5,
    width: "100%",
    height: "100vh"
  });

  const [hotspots, setHotspots] = useState([]);
  const [selectedSpot, setSelectedSpot] = useState(null);

  useEffect(() => {
    fetch("http://localhost:5000/api/news")
      .then(res => res.json())
      .then(data => {
        if (data.hotspots) {
          setHotspots(data.hotspots);
        } else {
          setHotspots([]);
        }
      })
      .catch(err => {
        console.error(err);
        setHotspots([]);
      });
  }, []);

  // Dummy button handler
  const handleComingSoon = (feature) => {
    alert(`${feature} feature coming soon!`);
  };

  return (
    <div style={{ fontFamily: "Segoe UI, Roboto, sans-serif", height: "100vh", display: "flex", flexDirection: "column" }}>
      
      {/* Top Navigation Bar */}
      <div style={{
        height: "60px",
        backgroundColor: "#1a1a1a",
        color: "#fff",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "0 20px",
        boxShadow: "0 2px 6px rgba(0,0,0,0.2)"
      }}>
        <h1 style={{ fontSize: "20px", margin: 0 }}>🌐 Geopolitical Dashboard</h1>
        <div>
          <button onClick={() => handleComingSoon("Analytics")} style={navButtonStyle}>Analytics</button>
          <button onClick={() => handleComingSoon("Filters")} style={navButtonStyle}>Filters</button>
          <button onClick={() => handleComingSoon("Reports")} style={navButtonStyle}>Reports</button>
          <button onClick={() => handleComingSoon("Settings")} style={navButtonStyle}>Settings</button>
        </div>
      </div>

      {/* Main Content: Sidebar + Map */}
      <div style={{ display: "flex", flex: 1 }}>
        
        {/* Sidebar */}
        <div style={{
          width: "320px",
          backgroundColor: "#fdfdfd",
          borderRight: "1px solid #e0e0e0",
          overflowY: "auto",
          padding: "20px",
          boxShadow: "2px 0 8px rgba(0,0,0,0.05)"
        }}>
          <h2 style={{ marginTop: 0, fontWeight: 600, color: "#333" }}>Latest Hotspots</h2>
          {hotspots.map((spot, i) => (
            <div key={i} style={{
              marginBottom: "18px",
              padding: "12px",
              borderRadius: "8px",
              backgroundColor: "#fff",
              transition: "transform 0.2s ease, box-shadow 0.2s ease",
              boxShadow: "0 2px 6px rgba(0,0,0,0.08)",
              cursor: "pointer"
            }}
            onClick={() => setSelectedSpot(spot)}
            onMouseEnter={e => e.currentTarget.style.transform = "scale(1.02)"}
            onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}
            >
              <strong style={{ color: "#222" }}>{spot.title}</strong>
              <br />
              <small style={{ color: "#666" }}>{spot.source}</small>
              <br />
              <span style={{ fontSize: "12px", color: "#0077cc" }}>Click to view on map</span>
            </div>
          ))}
        </div>

        {/* Map */}
        <div style={{ flex: 1 }}>
          <ReactMapGL
            {...viewport}
            mapStyle="mapbox://styles/mapbox/streets-v12"
            mapboxApiAccessToken={process.env.REACT_APP_MAPBOX_TOKEN}
            onViewportChange={setViewport}
          >
            {hotspots.map((spot, i) => (
              <Marker key={i} latitude={spot.lat} longitude={spot.lng}>
                <div
                  onClick={() => setSelectedSpot(spot)}
                  style={{
                    cursor: "pointer",
                    backgroundColor: "#e63946",
                    borderRadius: "50%",
                    width: "18px",
                    height: "18px",
                    border: "2px solid #fff",
                    boxShadow: "0 0 8px rgba(230,57,70,0.6)",
                    transition: "transform 0.2s ease"
                  }}
                  onMouseEnter={e => e.currentTarget.style.transform = "scale(1.3)"}
                  onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}
                />
              </Marker>
            ))}

            {selectedSpot && (
              <Popup
                latitude={selectedSpot.lat}
                longitude={selectedSpot.lng}
                onClose={() => setSelectedSpot(null)}
                closeOnClick={false}
                anchor="top"
              >
                <div style={{
                  maxWidth: "260px",
                  padding: "12px",
                  borderRadius: "8px",
                  backgroundColor: "#fff",
                  boxShadow: "0 4px 12px rgba(0,0,0,0.15)",
                  animation: "fadeIn 0.3s ease"
                }}>
                  <strong style={{ color: "#222" }}>{selectedSpot.title}</strong>
                  <br />
                  <small style={{ color: "#555" }}>{selectedSpot.source}</small>
                  <br />
                  <a href={selectedSpot.url} target="_blank" rel="noopener noreferrer" style={{ color: "#0077cc" }}>
                    Read more →
                  </a>
                </div>
              </Popup>
            )}
          </ReactMapGL>
        </div>
      </div>
    </div>
  );
}

// Reusable nav button style
const navButtonStyle = {
  backgroundColor: "#333",
  color: "#fff",
  border: "none",
  padding: "8px 12px",
  marginLeft: "10px",
  borderRadius: "4px",
  cursor: "pointer",
  fontSize: "14px",
  transition: "background-color 0.2s ease"
};

export default WorldMap;
